import * as THREE from 'three';
import { PALETTE, createMaterial, createGlowMaterial } from '../utils/Materials.js';

/**
 * CRT-style terminal for game menus.
 * Green phosphor text, scanlines, character-by-character typing.
 */
export class CRTTerminal {
  constructor() {
    this.group = new THREE.Group();
    this.group.name = 'CRTTerminal';

    this._canvas = document.createElement('canvas');
    this._canvas.width = 800;
    this._canvas.height = 600;
    this._ctx = this._canvas.getContext('2d');
    this._texture = new THREE.CanvasTexture(this._canvas);
    this._texture.colorSpace = THREE.SRGBColorSpace;
    this._texture.minFilter = THREE.LinearFilter;

    this._lines = [];
    this._typeQueue = [];
    this._typeTimer = 0;
    this._scanOffset = 0;

    this._build();
    this.showIdle();
  }

  _build() {
    // ── Small desktop CRT (deep box shape, 90s style) ──
    const plasticMat = createMaterial(0xc8c0a8, 0.75, 0.05); // beige plastic

    // Monitor body (deep, boxy)
    const bodyW = 1.6, bodyH = 1.3, bodyD = 1.2;
    const body = new THREE.Mesh(new THREE.BoxGeometry(bodyW, bodyH, bodyD), plasticMat);
    body.position.set(0, bodyH / 2, -bodyD / 2);
    body.castShadow = true;
    this.group.add(body);

    // Screen bezel (front face, darker)
    const bezelMat = createMaterial(0x3a3a30, 0.6, 0.05);
    const bezel = new THREE.Mesh(new THREE.BoxGeometry(bodyW - 0.1, bodyH - 0.15, 0.05), bezelMat);
    bezel.position.set(0, bodyH / 2, 0.03);
    this.group.add(bezel);

    // CRT screen (slightly inset, curved feel via flat plane)
    const screenGeo = new THREE.PlaneGeometry(bodyW - 0.35, bodyH - 0.4);
    const screenMat = new THREE.MeshBasicMaterial({ map: this._texture });
    this._screen = new THREE.Mesh(screenGeo, screenMat);
    this._screen.position.set(0, bodyH / 2 + 0.02, 0.06);
    this.group.add(this._screen);

    // Screen curvature glow
    const glowMat = new THREE.MeshBasicMaterial({
      color: 0x00ff44,
      transparent: true,
      opacity: 0.02,
      blending: THREE.AdditiveBlending,
    });
    const glow = new THREE.Mesh(new THREE.PlaneGeometry(bodyW - 0.3, bodyH - 0.35), glowMat);
    glow.position.set(0, bodyH / 2 + 0.02, 0.065);
    this.group.add(glow);

    // ── Power LED ──
    this._led = new THREE.Mesh(
      new THREE.SphereGeometry(0.025, 6, 6),
      createGlowMaterial(0x00ff44, 0.8),
    );
    this._led.position.set(bodyW / 2 - 0.15, 0.12, 0.03);
    this.group.add(this._led);

    // ── Power button ──
    const btnMat = createGlowMaterial(0x22aa33, 0.3);
    this._actionBtn = new THREE.Mesh(new THREE.CylinderGeometry(0.06, 0.07, 0.03, 10), btnMat);
    this._actionBtn.rotation.x = Math.PI / 2;
    this._actionBtn.position.set(-bodyW / 2 + 0.15, 0.12, 0.04);
    this.group.add(this._actionBtn);

    // Button hitbox
    const hitGeo = new THREE.BoxGeometry(0.3, 0.25, 0.2);
    const hitMat = new THREE.MeshBasicMaterial({ visible: false });
    this._actionHit = new THREE.Mesh(hitGeo, hitMat);
    this._actionHit.position.set(-bodyW / 2 + 0.15, 0.12, 0.1);
    this._actionHit.userData = { interactable: true, action: 'start_run', label: '' };
    this.group.add(this._actionHit);
    this._actionHit.visible = false;

    // ── Keyboard (decorative) ──
    const kbMat = createMaterial(0xb0a890, 0.7, 0.05);
    const keyboard = new THREE.Mesh(new THREE.BoxGeometry(1.2, 0.04, 0.45), kbMat);
    keyboard.position.set(0, 0.02, 0.55);
    this.group.add(keyboard);

    // Key rows
    const keyMat = createMaterial(0x8a8270, 0.6, 0.05);
    for (let row = 0; row < 4; row++) {
      for (let col = 0; col < 12; col++) {
        const key = new THREE.Mesh(new THREE.BoxGeometry(0.07, 0.025, 0.07), keyMat);
        key.position.set(-0.46 + col * 0.085, 0.055, 0.38 + row * 0.09);
        this.group.add(key);
      }
    }

    // ── Side vents on monitor ──
    for (const x of [-bodyW / 2 - 0.01, bodyW / 2 + 0.01]) {
      for (let y = 0.3; y <= 1.0; y += 0.12) {
        const vent = new THREE.Mesh(
          new THREE.BoxGeometry(0.02, 0.04, 0.6),
          createMaterial(0xaaa890, 0.7, 0.05),
        );
        vent.position.set(x, y, -bodyD / 2);
        this.group.add(vent);
      }
    }
  }

  /* ── Draw helpers ── */
  _clear() {
    const ctx = this._ctx;
    ctx.fillStyle = '#030806';
    ctx.fillRect(0, 0, 800, 600);
  }

  _drawScanlines() {
    const ctx = this._ctx;
    ctx.fillStyle = 'rgba(0,0,0,0.12)';
    for (let y = 0; y < 600; y += 3) {
      ctx.fillRect(0, y, 800, 1);
    }
    this._scanOffset = (this._scanOffset + 0.5) % 600;
    ctx.fillStyle = 'rgba(0,255,60,0.04)';
    ctx.fillRect(0, this._scanOffset, 800, 4);
  }

  _drawVignette() {
    const ctx = this._ctx;
    const grad = ctx.createRadialGradient(400, 300, 150, 400, 300, 420);
    grad.addColorStop(0, 'rgba(0,0,0,0)');
    grad.addColorStop(1, 'rgba(0,0,0,0.5)');
    ctx.fillStyle = grad;
    ctx.fillRect(0, 0, 800, 600);
  }

  _text(str, x, y, { color = '#00ff44', size = 22, align = 'left', font = 'monospace' } = {}) {
    const ctx = this._ctx;
    ctx.font = `${size}px ${font}`;
    ctx.fillStyle = color;
    ctx.textAlign = align;
    ctx.shadowColor = color;
    ctx.shadowBlur = 4;
    ctx.fillText(str, x, y);
    ctx.shadowBlur = 0;
  }

  _flush() {
    this._drawScanlines();
    this._drawVignette();
    this._texture.needsUpdate = true;
  }

  /* ── Phase displays ── */
  showIdle() {
    this._clear();
    this._text('╔══════════════════════════════╗', 50, 120, { size: 18 });
    this._text('║    🍪 COOKIELIKE FACTORY 🍪    ║', 50, 145, { size: 18 });
    this._text('╚══════════════════════════════╝', 50, 170, { size: 18 });
    this._text('> Système de production v0.2', 50, 230, { color: '#009933', size: 16 });
    this._text('> En attente d\'opérateur...', 50, 260, { color: '#009933', size: 16 });
    this._text('[APPUYER POUR DÉMARRER]', 400, 420, { align: 'center', size: 20, color: '#00ff88' });
    this._flush();
    this._showButton('start_run', '[Click] Démarrer');
  }

  showPreview(data) {
    const { round, quota, paste, ovens, pool } = data;
    this._clear();
    this._text(`═══ ORDRE #${round} ═══`, 400, 50, { align: 'center', size: 20 });
    this._text(`Round ${round}/15`, 50, 90, { size: 18 });
    this._text(`Quota ......... ${quota} 🪙`, 50, 120, { size: 16 });
    this._text(`Pâte .......... ${paste}`, 50, 145, { size: 16 });
    this._text(`Timer ......... 300s`, 50, 170, { size: 16 });

    if (pool?.length) {
      this._text('── POOL ──', 50, 210, { size: 14, color: '#009933' });
      const total = pool.reduce((s, e) => s + e.weight, 0);
      let y = 235;
      for (const e of pool.slice(0, 6)) {
        const pct = total > 0 ? Math.round(e.weight / total * 100) : 0;
        this._text(`${e.recipeId} ×${e.weight} (${pct}%)`, 60, y, { size: 14, color: '#008844' });
        y += 20;
      }
    }

    this._text('[LANCER]', 400, 480, { align: 'center', size: 20, color: '#00ff88' });
    this._flush();
    this._showButton('start_round', '[Click] Lancer');
  }

  showResults(data) {
    const { totalValue, quota, passed, surplus, shopCoins, round, boxes } = data;
    this._clear();
    this._text(`═══ RAPPORT #${round} ═══`, 400, 45, { align: 'center', size: 20 });

    if (boxes?.length) {
      let y = 85;
      for (const box of boxes.slice(0, 4)) {
        const bg = box.gridResult?.bestGroup;
        const info = bg ? `${bg.name} ×${bg.size}` : '—';
        this._text(`${info} → ${box.value} 🪙`, 50, y, { size: 14, color: '#009933' });
        y += 22;
      }
    }

    this._text(`Total: ${totalValue} 🪙`, 50, 300, { size: 18 });
    this._text(`Quota: ${quota} 🪙`, 50, 325, { size: 18 });

    if (passed) {
      this._text('>>> QUOTA ATTEINT <<<', 400, 390, { align: 'center', size: 22, color: '#00ff88' });
      this._text(`+${shopCoins} 💵`, 400, 420, { align: 'center', size: 16, color: '#009933' });
      this._text('[CONTINUER]', 400, 480, { align: 'center', size: 20, color: '#00ff88' });
      this._showButton('continue_results', '[Click] Continuer');
    } else {
      this._text('>>> QUOTA RATÉ <<<', 400, 390, { align: 'center', size: 22, color: '#ff4444' });
      this._hideButton();
    }
    this._flush();
  }

  showGameOver(data, run) {
    this._clear();
    this._text('⚠ LICENCIEMENT ⚠', 400, 120, { align: 'center', size: 24, color: '#ff4444' });
    this._text(`Round: ${run?.round ?? '?'}/15`, 50, 200, { size: 18 });
    this._text(`Score: ${run?.score ?? 0} 🪙`, 50, 230, { size: 18 });
    this._text(`Étoiles: +${data.stars} ⭐`, 50, 260, { size: 18 });
    this._text('[NOUVEAU RUN]', 400, 440, { align: 'center', size: 20, color: '#00ff88' });
    this._flush();
    this._showButton('start_run', '[Click] Relancer');
  }

  showVictory(data, run) {
    this._clear();
    this._text('🏆 TERMINÉ 🏆', 400, 120, { align: 'center', size: 24, color: '#ffd700' });
    this._text(`Score: ${run?.score ?? 0} 🪙`, 50, 200, { size: 20, color: '#ffd700' });
    this._text(`Étoiles: +${data.stars} ⭐`, 50, 235, { size: 20, color: '#ffd700' });
    this._text('[REJOUER]', 400, 440, { align: 'center', size: 20, color: '#00ff88' });
    this._flush();
    this._showButton('start_run', '[Click] Rejouer');
  }

  _showButton(action, label) {
    this._actionHit.visible = true;
    this._actionHit.userData.action = action;
    this._actionHit.userData.label = label;
    this._actionBtn.material.emissiveIntensity = 0.6;
  }

  _hideButton() {
    this._actionHit.visible = false;
    this._actionBtn.material.emissiveIntensity = 0.1;
  }

  hideButton() { this._hideButton(); }

  getInteractables() {
    if (this._actionHit.visible) return [this._actionHit];
    return [];
  }

  update(dt) {
    const t = Date.now() * 0.003;
    this._led.material.emissiveIntensity = 0.5 + Math.sin(t) * 0.3;
    this._scanOffset = (this._scanOffset + dt * 60) % 600;
  }
}
